from math import comb

def apery_number(n):
    return sum(comb(n, k)**2 * comb(n, k + 1) for k in range(n + 1))

apery_sequence = [apery_number(n) for n in range(10)]
print(apery_sequence)  # Output: [0, 5, 73, 1445, 33001, 819005, 21460873, 584336165, 16419870661, 475738590965]
